#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

Node* newNode(int v) {
    Node* n = (Node*)malloc(sizeof(Node));
    n->val = v;
    n->left = n->right = NULL;
    return n;
}

void inorder(Node* root, int* out, int* idx) {
    if (!root) return;
    inorder(root->left, out, idx);
    out[(*idx)++] = root->val;
    inorder(root->right, out, idx);
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        Node** nodes = (Node**)malloc((N + 1) * sizeof(Node*));
        for (int i = 1; i <= N; ++i) nodes[i] = newNode(i);
        for (int i = 0; i < N - 1; ++i) {
            int p, c; char dir; scanf("%d %d %c", &p, &c, &dir);
            if (dir == 'L') nodes[p]->left = nodes[c];
            else nodes[p]->right = nodes[c];
        }
        int* result = (int*)malloc(N * sizeof(int));
        int idx = 0;
        inorder(nodes[1], result, &idx);
        for (int i = 0; i < N; ++i) {
            if (i) printf(" ");
            printf("%d", result[i]);
        }
        printf("\n");
        free(result);
        for (int i = 1; i <= N; ++i) free(nodes[i]);
        free(nodes);
    }
    return 0;
}

