using namespace std;

struct Node {
    int val;
    Node* left = nullptr;
    Node* right = nullptr;
    Node(int v) : val(v) {}
};

void inorder(Node* root, vector<int>& out) {
    if (!root) return;
    inorder(root->left, out);
    out.push_back(root->val);
    inorder(root->right, out);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin >> T)) return 0;
    while (T--) {
        int N; cin >> N;
        vector<Node*> nodes(N + 1);
        for (int i = 1; i <= N; ++i) nodes[i] = new Node(i);
        for (int i = 0; i < N - 1; ++i) {
            int p, c; char dir; cin >> p >> c >> dir;
            if (dir == 'L') nodes[p]->left = nodes[c];
            else nodes[p]->right = nodes[c];
        }
        vector<int> ans; ans.reserve(N);
        inorder(nodes[1], ans);
        for (int i = 0; i < N; ++i) {
            if (i) cout << ' ';
            cout << ans[i];
        }
        cout << '\n';
        for (int i = 1; i <= N; ++i) delete nodes[i];
    }
    return 0;
}

